- countNeighbors checks Moore neighborhood (8 adjacent cells)
- nextGeneration filters live cells keeping those with 2 or 3 neighbors
- Dead cell birth not yet implemented

Current implementation:
```typescript
type Cell = [number, number];

const countNeighbors = (cell: Cell, cells: Cell[]): number =>
  cells.filter(
    (c) => Math.abs(c[0] - cell[0]) <= 1 && Math.abs(c[1] - cell[1]) <= 1 && !(c[0] === cell[0] && c[1] === cell[1])
  ).length;

export function nextGeneration(cells: Cell[]): Cell[] {
  return cells.filter((cell) => {
    const n = countNeighbors(cell, cells);
    return n === 2 || n === 3;
  });
}
